  'ai.hint.improve': { en: 'Ask me to improve your answer...', zh: '让我改进你的回答...', es: 'Pídeme que mejore tu respuesta...', fr: 'Demandez-moi d\'améliorer votre réponse...', de: 'Bitten Sie mich, Ihre Antwort zu verbessern...', ja: '回答の改善を依頼してください...', ko: '답변 개선을 요청하세요...', pt: 'Peça-me para melhorar sua resposta...', ar: 'اطلب مني تحسين إجابتك...', hi: 'मुझसे अपने उत्तर को सुधारने के लिए कहें...', ru: 'Попросите меня улучшить ваш ответ...', it: 'Chiedimi di migliorare la tua risposta...' },
